     1→import React, { useState, useRef, useMemo, useEffect } from 'react';
     2→import {
     3→  DndContext,
     4→  DragOverlay,
     5→  PointerSensor,
     6→  TouchSensor,
     7→  useSensor,
     8→  useSensors,
     9→  closestCorners,
    10→  type DragEndEvent,
    11→  type DragStartEvent,
    12→} from '@dnd-kit/core';
    13→import { Widget } from '../components/Widget';
    14→import { KeyboardShortcutsHelp } from '../components/KeyboardShortcutsHelp';
    15→import { ConfirmDialog } from '../components/ConfirmDialog';
    16→import { Toast } from '../components/Toast';
    17→import { useKanbanStore } from '../stores/useKanbanStore';
    18→import { useKanbanKeyboard } from '../hooks/useKanbanKeyboard';
    19→import { KanbanColumn } from './Kanban/KanbanColumn';
    20→import { KanbanCard } from './Kanban/KanbanCard';
    21→import { ColumnManager } from './Kanban/ColumnManager';
    22→import { CardDetailPanel } from './Kanban/CardDetailPanel';
    23→import { ListView } from './Kanban/ListView';
    24→import { ArchivedView } from './Kanban/ArchivedView';
    25→import { QuickAddModal } from './Kanban/QuickAddModal';
    26→import type { Task, TaskStatus } from '../types';
    27→
    28→/**
    29→ * Kanban Board Widget - React Version with Drag & Drop
    30→ *
    31→ * Features:
    32→ * - Three-column board (To Do, In Progress, Done)
    33→ * - Drag and drop tasks between columns
    34→ * - Task CRUD operations
    35→ * - Priority and due date tracking
    36→ * - Syncs with Calendar widget
    37→ * - Keyboard shortcuts for navigation and actions
    38→ */
    39→export const Kanban: React.FC = () => {
    40→  const { tasks, columns, moveTask, deleteTask, updateTask, undo, undoHistory, autoArchiveCompletedTasks, visibleColumns = 5, setVisibleColumns } = useKanbanStore();
    41→  const [activeTask, setActiveTask] = useState<Task | null>(null);
    42→  const [showColumnManager, setShowColumnManager] = useState(false);
    43→  const [columnManagerInitialId, setColumnManagerInitialId] = useState<string | undefined>();
    44→  const [showArchivedView, setShowArchivedView] = useState(false);
    45→  const [showQuickAdd, setShowQuickAdd] = useState(false);
    46→  const [toast, setToast] = useState<{ message: string; showUndo: boolean } | null>(null);
    47→  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
    48→  const [selectedTab, setSelectedTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity'>('subtasks');
    49→
    50→  // View mode state with persistence
    51→  const [viewMode, setViewMode] = useState<'board' | 'list'>(() => {
    52→    const saved = localStorage.getItem('kanban-view-mode');
    53→    return (saved as 'board' | 'list') || 'board';
    54→  });
    55→
    56→  // Filter state
    57→  const [searchQuery, setSearchQuery] = useState('');
    58→  const [selectedPriorities, setSelectedPriorities] = useState<Set<string>>(new Set());
    59→  const [selectedTags, setSelectedTags] = useState<Set<string>>(new Set());
    60→  const [showFilters, setShowFilters] = useState(false);
    61→
    62→  // Refs for columns to trigger their add forms
    63→  const columnRefs = useRef<Record<string, { triggerAdd: () => void }>>({});
    64→  const cardRefs = useRef<Record<string, { triggerEdit: () => void }>>({});
    65→
    66→  // Configure sensors for drag-drop (mouse + touch)
    67→  const sensors = useSensors(
    68→    useSensor(PointerSensor, {
    69→      activationConstraint: {
    70→        distance: 8, // 8px movement before drag starts
    71→      },
    72→    }),
    73→    useSensor(TouchSensor, {
    74→      activationConstraint: {
    75→        delay: 250, // 250ms long press
    76→        tolerance: 5, // 5px movement tolerance
    77→      },
    78→    })
    79→  );
    80→
    81→  // Sort columns by order
    82→  const sortedColumns = useMemo(() => {
    83→    return [...columns].sort((a, b) => a.order - b.order);
    84→  }, [columns]);
    85→
    86→  const columnStatuses = sortedColumns.map((col) => col.id);
    87→
    88→  // Get all unique tags from tasks
    89→  const allTags = useMemo(() => {
    90→    const tagSet = new Set<string>();
    91→    tasks.forEach((task) => task.tags.forEach((tag) => tagSet.add(tag)));
    92→    return Array.from(tagSet).sort();
    93→  }, [tasks]);
    94→
    95→  // Filter tasks based on search and filters
    96→  const filteredTasks = useMemo(() => {
    97→    return tasks.filter((task) => {
    98→      // Search filter (title, description, or card number)
    99→      if (searchQuery) {
   100→        const query = searchQuery.toLowerCase();
   101→
   102→        // Phase A: Support searching by card number (e.g., "KAN-1", "1", "kan1")
   103→        const cardNumberStr = task.cardNumber ? `KAN-${task.cardNumber}`.toLowerCase() : '';
   104→        const cardNumberSimple = task.cardNumber?.toString() || '';
   105→
   106→        const matchesSearch =
   107→          task.title.toLowerCase().includes(query) ||
   108→          task.description.toLowerCase().includes(query) ||
   109→          cardNumberStr.includes(query) ||
   110→          cardNumberSimple.includes(query);
   111→
   112→        if (!matchesSearch) return false;
   113→      }
   114→
   115→      // Priority filter
   116→      if (selectedPriorities.size > 0 && !selectedPriorities.has(task.priority)) {
   117→        return false;
   118→      }
   119→
   120→      // Tags filter
   121→      if (selectedTags.size > 0) {
   122→        const hasSelectedTag = task.tags.some((tag) => selectedTags.has(tag));
   123→        if (!hasSelectedTag) return false;
   124→      }
   125→
   126→      return true;
   127→    });
   128→  }, [tasks, searchQuery, selectedPriorities, selectedTags]);
   129→
   130→  // Toggle filter helpers
   131→  const togglePriority = (priority: string) => {
   132→    setSelectedPriorities((prev) => {
   133→      const newSet = new Set(prev);
   134→      if (newSet.has(priority)) {
   135→        newSet.delete(priority);
   136→      } else {
   137→        newSet.add(priority);
   138→      }
   139→      return newSet;
   140→    });
   141→  };
   142→
   143→  const toggleTag = (tag: string) => {
   144→    setSelectedTags((prev) => {
   145→      const newSet = new Set(prev);
   146→      if (newSet.has(tag)) {
   147→        newSet.delete(tag);
   148→      } else {
   149→        newSet.add(tag);
   150→      }
   151→      return newSet;
   152→    });
   153→  };
   154→
   155→  const clearFilters = () => {
   156→    setSearchQuery('');
   157→    setSelectedPriorities(new Set());
   158→    setSelectedTags(new Set());
   159→  };
   160→
   161→  const hasActiveFilters =
   162→    searchQuery || selectedPriorities.size > 0 || selectedTags.size > 0;
   163→
   164→  // Keyboard shortcuts
   165→  const {
   166→    selectedColumn,
   167→    selectedTaskId,
   168→    showHelp,
   169→    closeHelp,
   170→    pendingDeleteTask,
   171→    confirmDelete,
   172→    cancelDelete,
   173→  } = useKanbanKeyboard({
   174→    columns: columnStatuses,
   175→    tasks: filteredTasks, // Use filtered tasks for keyboard navigation
   176→    onAddTask: (status) => {
   177→      // Trigger the add form in the selected column
   178→      columnRefs.current[status]?.triggerAdd();
   179→    },
   180→    onEditTask: (task) => {
   181→      // Trigger edit mode for the selected task
   182→      cardRefs.current[task.id]?.triggerEdit();
   183→    },
   184→    onDeleteTask: (taskId) => {
   185→      deleteTask(taskId);
   186→    },
   187→  });
   188→
   189→  const handleDragStart = (event: DragStartEvent) => {
   190→    const taskId = event.active.id as string;
   191→    const task = tasks.find((t) => t.id === taskId);
   192→    setActiveTask(task || null);
   193→  };
   194→
   195→  const handleDragEnd = (event: DragEndEvent) => {
   196→    const { active, over } = event;
   197→
   198→    setActiveTask(null);
   199→
   200→    if (!over) return;
   201→
   202→    const taskId = active.id as string;
   203→    const newStatus = over.id as TaskStatus;
   204→
   205→    // Move task to new column
   206→    moveTask(taskId, newStatus);
   207→  };
   208→
   209→  const handleEditColumn = (columnId: string) => {
   210→    setColumnManagerInitialId(columnId);
   211→    setShowColumnManager(true);
   212→  };
   213→
   214→  // View mode persistence
   215→  useEffect(() => {
   216→    localStorage.setItem('kanban-view-mode', viewMode);
   217→  }, [viewMode]);
   218→
   219→  // Phase A: Auto-archive completed tasks on mount
   220→  useEffect(() => {
   221→    autoArchiveCompletedTasks();
   222→  }, []); // Run once on mount
   223→
   224→  // Phase A: Global keyboard shortcut for Quick Add (Cmd/Ctrl+K)
   225→  useEffect(() => {
   226→    const handleGlobalKeyDown = (e: KeyboardEvent) => {
   227→      // Cmd/Ctrl+K to open Quick Add
   228→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   229→        // Don't trigger if user is typing in an input/textarea
   230→        const target = e.target as HTMLElement;
   231→        if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) {
   232→          return;
   233→        }
   234→
   235→        e.preventDefault();
   236→        setShowQuickAdd(true);
   237→      }
   238→    };
   239→
   240→    window.addEventListener('keydown', handleGlobalKeyDown);
   241→    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
   242→  }, []);
   243→
   244→  // Listen for undo history changes and show toast
   245→  useEffect(() => {
   246→    if (undoHistory.length > 0) {
   247→      const lastEntry = undoHistory[undoHistory.length - 1];
   248→      setToast({
   249→        message: lastEntry.description,
   250→        showUndo: true,
   251→      });
   252→    }
   253→  }, [undoHistory]);
   254→
   255→  const handleUndo = () => {
   256→    undo();
   257→    setToast(null);
   258→  };
   259→
   260→  return (
   261→    <Widget
   262→      id="kanban"
   263→      title="Kanban Board"
   264→      category="Planning"
   265→      draggable={false}
   266→      headerAccessory={
   267→        <div className="flex items-center gap-1">
   268→          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary mr-2">
   269→            Columns:
   270→          </span>
   271→          {[3, 4, 5, 6, 7].map((count) => (
   272→            <button
   273→              key={count}
   274→              onClick={() => setVisibleColumns(count)}
   275→              className={`px-2 py-1 text-xs font-medium rounded transition-colors ${
   276→                visibleColumns === count
   277→                  ? 'bg-accent-blue text-white'
   278→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary hover:bg-neutral-200 dark:hover:bg-neutral-700'
   279→              }`}
   280→              title={`Show ${count} columns at once`}
   281→            >
   282→              {count}
   283→            </button>
   284→          ))}
   285→        </div>
   286→      }
   287→    >
   288→      {/* Filter Bar */}
   289→      <div className="mb-4 space-y-3">
   290→        {/* Search and Filter Toggle */}
   291→        <div className="flex gap-2">
   292→          <input
   293→            type="text"
   294→            value={searchQuery}
   295→            onChange={(e) => setSearchQuery(e.target.value)}
   296→            placeholder="Search tasks (by title, description, or KAN-#)..."
   297→            className="flex-1 px-4 py-2 text-sm border border-neutral-lightGray dark:border-neutral-darkGray rounded-lg bg-white dark:bg-neutral-charcoal text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-primary"
   298→          />
   299→          <button
   300→            onClick={() => setShowColumnManager(true)}
   301→            className="px-4 py-2 text-sm font-medium bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors whitespace-nowrap"
   302→            title="Manage Columns"
   303→          >
   304→            ⚙️ Columns
   305→          </button>
   306→          <button
   307→            onClick={() => setShowArchivedView(true)}
   308→            className="px-4 py-2 text-sm font-medium bg-surface-light-elevated dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary rounded-lg border border-border-light dark:border-border-dark hover:bg-surface-light dark:hover:bg-surface-dark-elevated transition-colors whitespace-nowrap"
   309→            title="View Archived Tasks"
   310→          >
   311→            📦 Archived
   312→          </button>
   313→          {/* View Toggle */}
   314→          <div className="flex rounded-lg overflow-hidden border border-border-light dark:border-border-dark">
   315→            <button
   316→              onClick={() => setViewMode('board')}
   317→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap ${
   318→                viewMode === 'board'
   319→                  ? 'bg-accent-blue text-white'
   320→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   321→              }`}
   322→              title="Board View"
   323→            >
   324→              📋 Board
   325→            </button>
   326→            <button
   327→              onClick={() => setViewMode('list')}
   328→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap border-l border-border-light dark:border-border-dark ${
   329→                viewMode === 'list'
   330→                  ? 'bg-accent-blue text-white'
   331→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   332→              }`}
   333→              title="List View"
   334→            >
   335→              📊 List
   336→            </button>
   337→          </div>
   338→          <button
   339→            onClick={() => setShowFilters(!showFilters)}
   340→            className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors whitespace-nowrap ${
   341→              showFilters || hasActiveFilters
   342→                ? 'bg-accent-primary text-white'
   343→                : 'bg-neutral-paleGray dark:bg-neutral-darkGray text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-lightGray dark:hover:bg-neutral-gray'
   344→            }`}
   345→          >
   346→            🔍 Filters {hasActiveFilters && `(${[...selectedPriorities, ...selectedTags].length})`}
   347→          </button>
   348→          {hasActiveFilters && (
   349→            <button
   350→              onClick={clearFilters}
   351→              className="px-4 py-2 text-sm font-medium bg-neutral-gray text-white rounded-lg hover:opacity-80 transition-opacity"
   352→            >
   353→              Clear
   354→            </button>
   355→          )}
   356→        </div>
   357→
   358→        {/* Advanced Filters (collapsible) */}
   359→        {showFilters && (
   360→          <div className="p-4 bg-neutral-paleGray dark:bg-neutral-darkGray rounded-lg space-y-3">
   361→            {/* Priority Filter */}
   362→            <div>
   363→              <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   364→                Priority
   365→              </label>
   366→              <div className="flex gap-2 flex-wrap">
   367→                {(['low', 'medium', 'high'] as const).map((priority) => (
   368→                  <button
   369→                    key={priority}
   370→                    onClick={() => togglePriority(priority)}
   371→                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
   372→                      selectedPriorities.has(priority)
   373→                        ? 'bg-accent-primary text-white ring-2 ring-accent-primary ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   374→                        : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-accent-primary'
   375→                    }`}
   376→                  >
   377→                    {priority.charAt(0).toUpperCase() + priority.slice(1)}
   378→                  </button>
   379→                ))}
   380→              </div>
   381→            </div>
   382→
   383→            {/* Tags Filter */}
   384→            {allTags.length > 0 && (
   385→              <div>
   386→                <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   387→                  Tags
   388→                </label>
   389→                <div className="flex gap-2 flex-wrap">
   390→                  {allTags.map((tag) => (
   391→                    <button
   392→                      key={tag}
   393→                      onClick={() => toggleTag(tag)}
   394→                      className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
   395→                        selectedTags.has(tag)
   396→                          ? 'bg-secondary-primary text-white ring-2 ring-secondary-primary ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   397→                          : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-secondary-primary'
   398→                      }`}
   399→                    >
   400→                      #{tag}
   401→                    </button>
   402→                  ))}
   403→                </div>
   404→              </div>
   405→            )}
   406→          </div>
   407→        )}
   408→
   409→        {/* Results Count */}
   410→        {hasActiveFilters && (
   411→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   412→            Showing {filteredTasks.length} of {tasks.length} tasks
   413→          </div>
   414→        )}
   415→      </div>
   416→
   417→      {/* Keyboard shortcuts hint */}
   418→      <div className="mb-3 flex items-center justify-between">
   419→        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary flex items-center gap-4">
   420→          <span>
   421→            Press <kbd className="px-2 py-0.5 text-xs font-mono bg-neutral-paleGray dark:bg-neutral-darkGray rounded border border-neutral-lightGray dark:border-neutral-gray">?</kbd> for keyboard shortcuts
   422→          </span>
   423→          <span className="hidden md:inline">
   424→            <kbd className="px-2 py-0.5 text-xs font-mono bg-neutral-paleGray dark:bg-neutral-darkGray rounded border border-neutral-lightGray dark:border-neutral-gray">⌘K</kbd> to quick add task
   425→          </span>
   426→        </div>
   427→      </div>
   428→
   429→      {viewMode === 'board' ? (
   430→        <DndContext
   431→          sensors={sensors}
   432→          collisionDetection={closestCorners}
   433→          onDragStart={handleDragStart}
   434→          onDragEnd={handleDragEnd}
   435→        >
   436→          <div className="kanban-board min-h-[500px] flex gap-4 overflow-x-auto pb-4 max-w-full">
   437→            {sortedColumns.map((column, index) => {
   438→              // Dynamic column width: always calculate based on visibleColumns setting
   439→              // If visibleColumns > actual columns, columns will be narrower (leaving space on right)
   440→              // If visibleColumns < actual columns, horizontal scrolling will be enabled
   441→              const columnWidth = `calc((100% - ${(visibleColumns - 1) * 16}px) / ${visibleColumns})`;
   442→
   443→              return (
   444→                <KanbanColumn
   445→                  key={column.id}
   446→                  id={column.id}
   447→                  title={column.title}
   448→                  color={column.color}
   449→                  wipLimit={column.wipLimit}
   450→                  tasks={filteredTasks.filter((task) => task.status === column.id)}
   451→                  selectedTaskId={selectedColumn === index ? selectedTaskId : undefined}
   452→                  columnWidth={columnWidth}
   453→                  onRegisterRef={(ref) => {
   454→                    columnRefs.current[column.id] = ref;
   455→                  }}
   456→                  onRegisterCardRef={(taskId, ref) => {
   457→                    cardRefs.current[taskId] = ref;
   458→                  }}
   459→                  onCardClick={(task, tab) => {
   460→                    setSelectedTask(task);
   461→                    if (tab) setSelectedTab(tab);
   462→                  }}
   463→                  onEditColumn={handleEditColumn}
   464→                />
   465→              );
   466→            })}
   467→          </div>
   468→
   469→          {/* Drag overlay - shows ghost of dragged card */}
   470→          <DragOverlay>
   471→            {activeTask ? (
   472→              <div className="opacity-80 rotate-3 scale-105 transition-transform">
   473→                <KanbanCard task={activeTask} isDragging />
   474→              </div>
   475→            ) : null}
   476→          </DragOverlay>
   477→        </DndContext>
   478→      ) : (
   479→        <ListView
   480→          tasks={filteredTasks}
   481→          columns={columns}
   482→          onTaskClick={(task) => setSelectedTask(task)}
   483→        />
   484→      )}
   485→
   486→      {/* Keyboard Shortcuts Help Modal */}
   487→      <KeyboardShortcutsHelp isOpen={showHelp} onClose={closeHelp} />
   488→
   489→      {/* Delete Confirmation Dialog */}
   490→      {pendingDeleteTask && (
   491→        <ConfirmDialog
   492→          isOpen={true}
   493→          onClose={cancelDelete}
   494→          onConfirm={confirmDelete}
   495→          title="Delete Task"
   496→          message={`Are you sure you want to delete "${pendingDeleteTask.title}"? This action cannot be undone.`}
   497→          variant="danger"
   498→        />
   499→      )}
   500→
   501→      {/* Column Manager Modal */}
   502→      <ColumnManager
   503→        isOpen={showColumnManager}
   504→        onClose={() => {
   505→          setShowColumnManager(false);
   506→          setColumnManagerInitialId(undefined);
   507→        }}
   508→        initialEditingColumnId={columnManagerInitialId}
   509→      />
   510→
   511→      {/* Toast Notification */}
   512→      {toast && (
   513→        <Toast
   514→          message={toast.message}
   515→          action={toast.showUndo ? { label: 'Undo', onClick: handleUndo } : undefined}
   516→          onClose={() => setToast(null)}
   517→        />
   518→      )}
   519→
   520→      {/* Card Detail Panel */}
   521→      <CardDetailPanel
   522→        task={selectedTask}
   523→        isOpen={!!selectedTask}
   524→        onClose={() => {
   525→          setSelectedTask(null);
   526→          setSelectedTab('subtasks'); // Reset to default tab
   527→        }}
   528→        onSave={(taskId, updates) => {
   529→          updateTask(taskId, updates);
   530→        }}
   531→        columns={columns}
   532→        initialTab={selectedTab}
   533→        onCardClick={(task) => {
   534→          setSelectedTask(task);
   535→        }}
   536→      />
   537→
   538→      {/* Archived View */}
   539→      <ArchivedView
   540→        isOpen={showArchivedView}
   541→        onClose={() => setShowArchivedView(false)}
   542→      />
   543→
   544→      {/* Quick Add Modal (Phase A: Quick Add Cmd+K) */}
   545→      <QuickAddModal
   546→        isOpen={showQuickAdd}
   547→        onClose={() => setShowQuickAdd(false)}
   548→      />
   549→    </Widget>
   550→  );
   551→};
   552→

