   161→
   162→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   163→        if (newStatus === 'done') {
   164→          const blockers = get().getBlockers(id);
   165→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   166→
   167→          if (incompleteBlockers.length > 0) {
   168→            console.warn(
   169→              `Cannot complete task "${oldTask.title}": Blocked by ${incompleteBlockers.length} incomplete task(s)`
   170→            );
   171→            // TODO: Show toast notification in UI
   172→            return; // Prevent move
   173→          }
   174→        }
   175→
   176→        // PHASE A: Track when task is completed (for auto-archive)
   177→        const updates: Partial<Task> = { status: newStatus };
   178→        if (newStatus === 'done' && oldTask.status !== 'done') {
   179→          updates.lastCompletedAt = new Date().toISOString();
   180→        }
   181→
   182→        set((state) => ({
   183→          tasks: state.tasks.map((task) =>
   184→            task.id === id ? { ...task, ...updates } : task
   185→          ),
   186→        }));
   187→
   188→        // Log move
   189→        get().logActivity(id, {
