   797→        // Prevent self-dependency
   798→        if (sourceTaskId === targetTaskId) {
   799→          console.error('Task cannot depend on itself');
   800→          return;
   801→        }
   802→
   803→        // Check for circular dependency
   804→        const dependencies = get().dependencies || [];
   805→        const wouldCreateCycle = (source: string, target: string): boolean => {
   806→          if (source === target) return true;
   807→          const childDeps = dependencies.filter((d) => d.sourceTaskId === target);
   808→          return childDeps.some((d) => wouldCreateCycle(source, d.targetTaskId));
   809→        };
   810→
   811→        if (wouldCreateCycle(sourceTaskId, targetTaskId)) {
   812→          console.error('This would create a circular dependency');
   813→          return;
   814→        }
   815→
   816→        const newDependency: SimpleTaskDependency = {
   817→          id: `dep-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
   818→          sourceTaskId,
   819→          targetTaskId,
   820→          createdAt: new Date().toISOString(),
   821→        };
   822→
   823→        set((state) => ({
   824→          dependencies: [...(state.dependencies || []), newDependency],
   825→        }));
   826→
   827→        // Log activity for both tasks
   828→        get().logActivity(sourceTaskId, {
   829→          action: 'created',
   830→          field: 'dependency',
   831→          newValue: `Blocks task ${targetTaskId}`,
   832→        });
   833→
   834→        get().logActivity(targetTaskId, {
   835→          action: 'created',
   836→          field: 'dependency',
   837→          newValue: `Blocked by task ${sourceTaskId}`,
   838→        });
   839→      },
   840→
   841→      removeDependency: (dependencyId) => {
   842→        const dependency = get().dependencies?.find((d) => d.id === dependencyId);
   843→
   844→        set((state) => ({
   845→          dependencies: (state.dependencies || []).filter((d) => d.id !== dependencyId),
   846→        }));
   847→
   848→        // Log activity
   849→        if (dependency) {
   850→          get().logActivity(dependency.sourceTaskId, {
   851→            action: 'updated',
   852→            field: 'dependency',
   853→            oldValue: `Blocks task ${dependency.targetTaskId}`,
   854→          });
   855→
   856→          get().logActivity(dependency.targetTaskId, {
   857→            action: 'updated',
   858→            field: 'dependency',
   859→            oldValue: `Blocked by task ${dependency.sourceTaskId}`,
   860→          });
   861→        }
