   915→          tasks: [...state.tasks, restoredTask as Task],
   916→        }));
   917→
   918→        // Log restore action
   919→        get().logActivity(id, {
   920→          action: 'updated',
   921→          field: 'archived',
   922→          oldValue: 'true',
   923→          newValue: 'false',
   924→        });
   925→      },
